type Locale = 'en' | 'ja';

interface LanguageContextType {
  locale: Locale;
  setLocale: (locale: string) => void;
  t: (key: string) => string;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

/**
 * Fix: Implement LanguageProvider to fix missing exported member error
 * This provider wraps the application and provides the internationalization context.
 */
export const LanguageProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [locale, setLocaleState] = useState<Locale>('ja');

  const setLocale = (l: string) => {
    if (l === 'en' || l === 'ja') {
      setLocaleState(l);
    }
  };

  const t = useCallback((key: string): string => {
    const messages = locale === 'en' ? enMessages : jaMessages;
    const keys = key.split('.');
    let value: any = messages;
    for (const k of keys) {
      if (value && typeof value === 'object' && k in value) {
        value = value[k];
      } else {
        return key; // Fallback to the key itself if not found
      }
    }
    return typeof value === 'string' ? value : key;
  }, [locale]);

  return (
    <LanguageContext.Provider value={{ locale, setLocale, t }}>
      {children}
    </LanguageContext.Provider>
  );
};

/**
 * Fix: Implement useLanguage to fix missing exported member error
 * This hook allows components to access the current locale and translation function.
 */
export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (context === undefined) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};
